const EXACT_TEXT_LOOKUP = new Map(
  Object.entries(EXACT_TEXT_TRANSLATIONS).map(([source, translations]) => [normalizeText(source), translations]),
);

function normalizeText(value: string) {
  return value.replace(/\s+/g, ' ').trim();
}

function preserveWhitespace(original: string, translated: string) {
  const leading = original.match(/^\s*/)?.[0] ?? '';
  const trailing = original.match(/\s*$/)?.[0] ?? '';
  return `${leading}${translated}${trailing}`;
}

function resolveTranslation(language: string, translations: TranslationRecord | undefined) {
  if (!translations) return null;
  const exact = translations[language as SupportedLanguage];
  if (exact) return exact;
  const baseLanguage = language.split('-')[0] as SupportedLanguage;
  return translations[baseLanguage] ?? null;
}

function translateExactCore(language: string, text: string) {
  return resolveTranslation(language, EXACT_TEXT_LOOKUP.get(normalizeText(text)));
}

export function getLegacyStaticTranslationsForLanguage(language: string) {
  const baseLanguage = language.split('-')[0];
  const entries = Object.entries(EXACT_TEXT_TRANSLATIONS)
    .map(([source, translations]) => {
      const value = translations[language] ?? translations[baseLanguage] ?? null;
      return value ? [source, value] : null;
    })
    .filter((entry): entry is [string, string] => !!entry);

  return Object.fromEntries(entries);
}

function translateCount(language: string, count: number, singularKey: string, pluralKey: string) {
  const label = translateExactCore(language, count === 1 ? singularKey : pluralKey) ?? (count === 1 ? singularKey : pluralKey);
  return `${count} ${label}`;
}

type DynamicTranslator = (language: string, text: string) => string | null;

const DYNAMIC_TRANSLATORS: DynamicTranslator[] = [
  (language, text) => {
    const match = text.match(/^(\d+)\s+pending\s+·\s+(\d+)\s+done$/i);
    if (!match) return null;
    const pendingLabel = translateExactCore(language, 'pending') ?? 'pending';
    const doneLabel = translateExactCore(language, 'done') ?? 'done';
    return `${match[1]} ${pendingLabel} · ${match[2]} ${doneLabel}`;
  },
  (language, text) => {
    const match = text.match(/^(\d+)\/(\d+)\s+done$/i);
    if (!match) return null;
    const doneLabel = translateExactCore(language, 'done') ?? 'done';
    return `${match[1]}/${match[2]} ${doneLabel}`;
  },
  (language, text) => {
    const match = text.match(/^(\d+)\s+task(?:s)?\s+pending\s+today$/i);
    if (!match) return null;
    const count = Number(match[1]);
    const pendingLabel = translateExactCore(language, 'pending') ?? 'pending';
    const todayLabel = translateExactCore(language, 'Today') ?? 'Today';
    return `${translateCount(language, count, 'task', 'tasks')} ${pendingLabel} ${todayLabel.toLowerCase()}`;
  },
  (language, text) => {
    const match = text.match(/^(\d+)\s+rolled over$/i);
    if (!match) return null;
    return `${match[1]} ${translateExactCore(language, 'rolled over') ?? 'rolled over'}`;
  },
  (language, text) => {
    const match = text.match(/^(\d+)\s+members?$/i);
    if (!match) return null;
    return translateCount(language, Number(match[1]), 'member', 'members');
  },
  (language, text) => {
    const match = text.match(/^(\d+)\s+comment(?:s)?$/i);
    if (!match) return null;
    return translateCount(language, Number(match[1]), 'comment', 'comments');
  },
  (language, text) => {
    const match = text.match(/^(\d+)\s+vote(?:s)?$/i);
    if (!match) return null;
    return translateCount(language, Number(match[1]), 'vote', 'votes');
  },
  (language, text) => {
    const match = text.match(/^Today at\s+(.+)$/);
    if (!match) return null;
    const todayLabel = translateExactCore(language, 'Today') ?? 'Today';
    return `${todayLabel} ${match[1]}`;
  },
  (language, text) => {
    const match = text.match(/^Yesterday at\s+(.+)$/);
    if (!match) return null;
    const yesterdayLabel = translateExactCore(language, 'Yesterday') ?? 'Yesterday';
    return `${yesterdayLabel} ${match[1]}`;
  },
  (language, text) => {
    const match = text.match(/^Last updated:\s+(.+)$/);
    if (!match) return null;
    const label = translateExactCore(language, 'Last updated:') ?? 'Last updated:';
    return `${label} ${match[1]}`;
  },
  (language, text) => {
    const match = text.match(/^Owner:\s+(.+)$/);
    if (!match) return null;
    const label = translateExactCore(language, 'Owner:') ?? 'Owner:';
    return `${label} ${match[1]}`;
  },
  (language, text) => {
    const match = text.match(/^Collaborators:\s+(\d+)$/);
    if (!match) return null;
    const label = translateExactCore(language, 'Collaborators:') ?? 'Collaborators:';
    return `${label} ${match[1]}`;
  },
  (language, text) => {
    const match = text.match(/^Delete\s+"(.+)"$/);
    if (!match) return null;
    const label = translateExactCore(language, 'Delete') ?? 'Delete';
    return `${label} "${match[1]}"`;
  },
];

export function translateStaticAppText(language: string, originalText: string) {
  const normalized = normalizeText(originalText);
  if (!normalized) return null;

  const exactTranslation = translateExactCore(language, normalized);
  if (exactTranslation) {
    return preserveWhitespace(originalText, exactTranslation);
  }

  for (const translator of DYNAMIC_TRANSLATORS) {
    const translated = translator(language, normalized);
    if (translated) {
      return preserveWhitespace(originalText, translated);
    }
  }

  return null;
}